{
    "@context": {"ids": "https://w3id.org/idsa/core/", "idsc": "https://w3id.org/idsa/code/"},
    "@id": "https://w3id.org/idsa/autogen/representation/meta_{{uuid_meta}}",
    "@type": "ids:TextRepresentation",
    "ids:title": [{"@value": "Metadata Representation", "@type": "http://www.w3.org/2001/XMLSchema#string"}],
    "ids:description": [{"@value": "Metadata for Ollama reasoning. Columns: srcip, dstip, proto, state, dur, sbytes, dbytes...", "@type": "http://www.w3.org/2001/XMLSchema#string"}],
    "ids:mediaType": {"@id": "https://w3id.org/idsa/code/JSON"},
    "ids:instance": [{
        "@type": "ids:Artifact",
        "@id": "http://w3id.org/engrd/connector/artifact/metadata_{{uuid_meta}}",
        "ids:fileName": "metadata.json",
        "ids:creationDate": {"@value": "2026-01-01T00:00:00Z", "@type": "http://www.w3.org/2001/XMLSchema#dateTimeStamp"}
    }]
}

{
    "@context": {"ids": "https://w3id.org/idsa/core/", "idsc": "https://w3id.org/idsa/code/"},
    "@id": "https://w3id.org/idsa/autogen/representation/exec_{{uuid_exec}}",
    "@type": "ids:TextRepresentation",
    "ids:title": [{"@value": "Execution Representation", "@type": "http://www.w3.org/2001/XMLSchema#string"}],
    "ids:description": [{"@value": "Instancia del dataset en sí para entrenamiento FL", "@type": "http://www.w3.org/2001/XMLSchema#string"}],
    "ids:mediaType": {"@id": "https://w3id.org/idsa/code/CSV"},
    "ids:instance": [{
        "@type": "ids:Artifact",
        "@id": "http://w3id.org/engrd/connector/artifact/dataset_{{uuid_exec}}",
        "ids:fileName": "{{dataset_filename}}",
        "ids:creationDate": {"@value": "2026-01-01T00:00:00Z", "@type": "http://www.w3.org/2001/XMLSchema#dateTimeStamp"}
    }]
}

{
    "@id": "https://w3id.org/idsa/autogen/contractOffer/dataset_{{uuid_contract}}",
    "@type": "ids:ContractOffer",
    "ids:provider": {"@id": "{{Coordinator_Connector_URI}}"},
    "ids:permission": [{
        "@type": "ids:Permission",
        "@id": "https://w3id.org/idsa/autogen/permission/{{uuid_perm}}",
        "ids:action": [{"@id": "https://w3id.org/idsa/code/USE"}],
        "ids:title": [{"@value": "Local FL Training Only", "@type": "http://www.w3.org/2001/XMLSchema#string"}],
        "ids:description": [{"@value": "Data strictly restricted for Federated Learning algorithms. No raw data access or transfer allowed.", "@type": "http://www.w3.org/2001/XMLSchema#string"}],
        "ids:target": {"@id": "{{datasetArtifact}}"},
        "ids:constraint": [{
            "@type": "ids:Constraint",
            "@id": "https://w3id.org/idsa/autogen/constraint/local_only",
            "ids:leftOperand": {"@id": "https://w3id.org/idsa/code/PURPOSE"},
            "ids:operator": {"@id": "https://w3id.org/idsa/code/SAME_AS"},
            "ids:rightOperand": {"@value": "Federated_Learning_Local_Only", "@type": "http://www.w3.org/2001/XMLSchema#string"}
        }]
    }],
    "ids:prohibition": [{
        "@type": "ids:Prohibition",
        "@id": "https://w3id.org/idsa/autogen/prohibition/no_distribute",
        "ids:action": [{"@id": "https://w3id.org/idsa/code/DISTRIBUTE"}],
        "ids:target": {"@id": "{{datasetArtifact}}"}
    }]
}
